// BiometricAuth.js
import React, { useState, useEffect, useCallback, createContext, useContext } from 'react';
import {
  View,
  Text,
  TextInput,
  TouchableOpacity,
  StyleSheet,
  Alert,
  ActivityIndicator,
  Platform,
} from 'react-native';
import ReactNativeBiometrics, { BiometryTypes } from 'react-native-biometrics';
import AsyncStorage from '@react-native-async-storage/async-storage';

const rnBiometrics = new ReactNativeBiometrics({ allowDeviceCredentials: false });

const STORAGE_KEYS = {
  SESSION_TOKEN: '@auth_session_token',
  BIOMETRIC_KEY_EXISTS: '@biometric_key_exists',
  USER_EMAIL: '@user_email',
};

// --- Secure Session Manager ---
// This module handles cryptographic key creation, signing challenges,
// and session token management. Biometric success is bound to
// a cryptographic signature verification, not a simple boolean flag.

const SecureSessionManager = {
  async createBiometricKey() {
    try {
      const { publicKey } = await rnBiometrics.createKeys();
      await AsyncStorage.setItem(STORAGE_KEYS.BIOMETRIC_KEY_EXISTS, 'true');
      return publicKey;
    } catch (error) {
      console.error('Failed to create biometric keys:', error);
      throw error;
    }
  },

  async deleteBiometricKey() {
    try {
      await rnBiometrics.deleteKeys();
      await AsyncStorage.removeItem(STORAGE_KEYS.BIOMETRIC_KEY_EXISTS);
    } catch (error) {
      console.error('Failed to delete biometric keys:', error);
    }
  },

  async biometricKeyExists() {
    try {
      const { keysExist } = await rnBiometrics.biometricKeysExist();
      const flagExists = await AsyncStorage.getItem(STORAGE_KEYS.BIOMETRIC_KEY_EXISTS);
      return keysExist && flagExists === 'true';
    } catch {
      return false;
    }
  },

  generateChallenge() {
    // In production, this challenge should come from your backend server
    const timestamp = Date.now();
    const random = Math.random().toString(36).substring(2, 15);
    return `auth_challenge_${timestamp}_${random}`;
  },

  async signChallengeWithBiometrics(promptMessage) {
    const challenge = this.generateChallenge();

    try {
      const { success, signature } = await rnBiometrics.createSignature({
        promptMessage: promptMessage || 'Authenticate to continue',
        payload: challenge,
      });

      if (!success || !signature) {
        return { success: false, error: 'Biometric signature failed' };
      }

      // In production, send { challenge, signature, publicKey } to your backend
      // for cryptographic verification. The backend should:
      // 1. Verify the signature against the stored public key
      // 2. Verify the challenge hasn't been used before (replay protection)
      // 3. Verify the challenge timestamp is recent
      // 4. Return a session token upon successful verification

      // Simulated backend verification and token generation
      const sessionToken = await this.simulateBackendVerification(challenge, signature);

      return { success: true, sessionToken, challenge, signature };
    } catch (error) {
      console.error('Biometric signature error:', error);
      return { success: false, error: error.message };
    }
  },

  async simulateBackendVerification(challenge, signature) {
    // ============================================================
    // PRODUCTION IMPLEMENTATION:
    // Replace this with an actual API call to your backend:
    //
    // const response = await fetch('https://your-api.com/auth/biometric-verify', {
    //   method: 'POST',
    //   headers: { 'Content-Type': 'application/json' },
    //   body: JSON.stringify({
    //     challenge,
    //     signature,
    //     publicKey: await this.getStoredPublicKey(),
    //   }),
    // });
    // const data = await response.json();
    // if (!data.verified) throw new Error('Server verification failed');
    // return data.sessionToken;
    // ============================================================

    // Simulated: generate a token that encodes the verification proof
    const tokenPayload = {
      verified: true,
      challenge,
      signatureHash: this.hashString(signature),
      issuedAt: Date.now(),
      expiresAt: Date.now() + 24 * 60 * 60 * 1000, // 24 hours
    };

    return btoa(JSON.stringify(tokenPayload));
  },

  hashString(str) {
    let hash = 0;
    for (let i = 0; i < str.length; i++) {
      const char = str.charCodeAt(i);
      hash = ((hash << 5) - hash) + char;
      hash |= 0;
    }
    return hash.toString(16);
  },

  async storeSessionToken(token) {
    await AsyncStorage.setItem(STORAGE_KEYS.SESSION_TOKEN, token);
  },

  async getSessionToken() {
    try {
      const token = await AsyncStorage.getItem(STORAGE_KEYS.SESSION_TOKEN);
      if (!token) return null;

      // Validate token hasn't expired
      try {
        const payload = JSON.parse(atob(token));
        if (payload.expiresAt && Date.now() > payload.expiresAt) {
          await this.clearSession();
          return null;
        }
        if (!payload.verified || !payload.signatureHash) {
          await this.clearSession();
          return null;
        }
      } catch {
        await this.clearSession();
        return null;
      }

      return token;
    } catch {
      return null;
    }
  },

  async clearSession() {
    await AsyncStorage.multiRemove([
      STORAGE_KEYS.SESSION_TOKEN,
    ]);
  },

  async fullLogout() {
    await this.clearSession();
    await this.deleteBiometricKey();
    await AsyncStorage.removeItem(STORAGE_KEYS.USER_EMAIL);
  },
};

// --- Auth Context ---

const AuthContext = createContext(null);

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

export const AuthProvider = ({ children }) => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [sessionToken, setSessionToken] = useState(null);
  const [userEmail, setUserEmail] = useState(null);

  useEffect(() => {
    checkExistingSession();
  }, []);

  const checkExistingSession = async () => {
    try {
      const token = await SecureSessionManager.getSessionToken();
      const email = await AsyncStorage.getItem(STORAGE_KEYS.USER_EMAIL);

      if (token) {
        setSessionToken(token);
        setUserEmail(email);
        setIsAuthenticated(true);
      }
    } catch (error) {
      console.error('Session check failed:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const authenticateWithBiometrics = async () => {
    const result = await SecureSessionManager.signChallengeWithBiometrics(
      'Verify your identity'
    );

    if (result.success) {
      await SecureSessionManager.storeSessionToken(result.sessionToken);
      setSessionToken(result.sessionToken);
      setIsAuthenticated(true);
      return { success: true };
    }

    return { success: false, error: result.error };
  };

  const authenticateWithPassword = async (email, password) => {
    // ============================================================
    // PRODUCTION: Replace with actual API authentication
    // const response = await fetch('https://your-api.com/auth/login', {
    //   method: 'POST',
    //   headers: { 'Content-Type': 'application/json' },
    //   body: JSON.stringify({ email, password }),
    // });
    // const data = await response.json();
    // if (!data.success) throw new Error(data.message);
    // return data.sessionToken;
    // ============================================================

    if (!email || !password) {
      return { success: false, error: 'Email and password are required' };
    }

    // Simulated password auth
    if (password.length < 4) {
      return { success: false, error: 'Invalid credentials' };
    }

    const tokenPayload = {
      verified: true,
      method: 'password',
      signatureHash: SecureSessionManager.hashString(email + Date.now()),
      issuedAt: Date.now(),
      expiresAt: Date.now() + 24 * 60 * 60 * 1000,
    };
    const token = btoa(JSON.stringify(tokenPayload));

    await SecureSessionManager.storeSessionToken(token);
    await AsyncStorage.setItem(STORAGE_KEYS.USER_EMAIL, email);
    setSessionToken(token);
    setUserEmail(email);
    setIsAuthenticated(true);

    return { success: true };
  };

  const enrollBiometrics = async () => {
    try {
      const publicKey = await SecureSessionManager.createBiometricKey();
      // In production, send publicKey to your backend to associate with the user
      // await fetch('https://your-api.com/auth/enroll-biometric', {
      //   method: 'POST',
      //   headers: {
      //     'Content-Type': 'application/json',
      //     'Authorization': `Bearer ${sessionToken}`,
      //   },
      //   body: JSON.stringify({ publicKey }),
      // });
      return { success: true, publicKey };
    } catch (error) {
      return { success: false, error: error.message };
    }
  };

  const logout = async () => {
    await SecureSessionManager.fullLogout();
    setIsAuthenticated(false);
    setSessionToken(null);
    setUserEmail(null);
  };

  return (
    <AuthContext.Provider
      value={{
        isAuthenticated,
        isLoading,
        sessionToken,
        userEmail,
        authenticateWithBiometrics,
        authenticateWithPassword,
        enrollBiometrics,
        logout,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
};

// --- Biometric Login Screen ---

const BiometricLoginScreen = ({ onPasswordFallback }) => {
  const { authenticateWithBiometrics } = useAuth();
  const [biometryType, setBiometryType] = useState(null);
  const [isAuthenticating, setIsAuthenticating] = useState(false);
  const [error, setError] = useState(null);

  useEffect(() => {
    checkBiometricAvailability();
  }, []);

  const checkBiometricAvailability = async () => {
    try {
      const { available, biometryType: type } = await rnBiometrics.isSensorAvailable();
      if (available) {
        setBiometryType(type);
      }
    } catch (err) {
      console.error('Biometric check failed:', err);
    }
  };

  const handleBiometricAuth = async () => {
    setIsAuthenticating(true);
    setError(null);

    try {
      const keyExists = await SecureSessionManager.biometricKeyExists();
      if (!keyExists) {
        setError('Biometric enrollment required. Please log in with password first.');
        setIsAuthenticating(false);
        return;
      }

      const result = await authenticateWithBiometrics();
      if (!result.success) {
        setError(result.error || 'Authentication failed. Please try again.');
      }
    } catch (err) {
      setError('An unexpected error occurred.');
      console.error('Biometric auth error:', err);
    } finally {
      setIsAuthenticating(false);
    }
  };

  const getBiometryLabel = () => {
    switch (biometryType) {
      case BiometryTypes.FaceID:
        return 'Face ID';
      case BiometryTypes.TouchID:
        return 'Touch ID';
      case BiometryTypes.Biometrics:
        return 'Fingerprint';
      default:
        return 'Biometrics';
    }
  };

  const getBiometryIcon = () => {
    switch (biometryType) {
      case BiometryTypes.FaceID:
        return '👤';
      case BiometryTypes.TouchID:
      case BiometryTypes.Biometrics:
        return '👆';
      default:
        return '🔐';
    }
  };

  return (
    <View style={styles.container}>
      <View style={styles.headerContainer}>
        <Text style={styles.appTitle}>SecureApp</Text>
        <Text style={styles.subtitle}>Welcome back</Text>
      </View>

      {biometryType && (
        <View style={styles.biometricContainer}>
          <TouchableOpacity
            style={[styles.biometricButton, isAuthenticating && styles.buttonDisabled]}
            onPress={handleBiometricAuth}
            disabled={isAuthenticating}
            activeOpacity={0.7}
          >
            {isAuthenticating ? (
              <ActivityIndicator size="large" color="#FFFFFF" />
            ) : (
              <>
                <Text style={styles.biometricIcon}>{getBiometryIcon()}</Text>
                <Text style={styles.biometricButtonText}>
                  Sign in with {getBiometryLabel()}
                </Text>
              </>
            )}
          </TouchableOpacity>

          <Text style={styles.securityNote}>
            🔒 Secured with cryptographic signature verification
          </Text>
        </View>
      )}

      {error && (
        <View style={styles.errorContainer}>
          <Text style={styles.errorText}>{error}</Text>
        </View>
      )}

      <TouchableOpacity
        style={styles.fallbackButton}
        onPress={onPasswordFallback}
        activeOpacity={0.7}
      >
        <Text style={styles.fallbackButtonText}>
          {biometryType ? 'Use password instead' : 'Sign in with password'}
        </Text>
      </TouchableOpacity>

      {!biometryType && (
        <Text style={styles.noBiometricText}>
          Biometric authentication is not available on this device.
          Please sign in with your password.
        </Text>
      )}
    </View>
  );
};

// --- Password Login Screen ---

const PasswordLoginScreen = ({ onBack, showBackButton }) => {
  const { authenticateWithPassword, enrollBiometrics } = useAuth();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState(null);

  const handlePasswordLogin = async () => {
    setIsLoading(true);
    setError(null);

    try {
      const result = await authenticateWithPassword(email, password);

      if (result.success) {
        // After successful password login, offer biometric enrollment
        await offerBiometricEnrollment();
      } else {
        setError(result.error || 'Login failed');
      }
    } catch (err) {
      setError('An unexpected error occurred.');
      console.error('Password login error:', err);
    } finally {
      setIsLoading(false);
    }
  };

  const offerBiometricEnrollment = async () => {
    try {
      const { available, biometryType } = await rnBiometrics.isSensorAvailable();

      if (!available) return;

      const keyExists = await SecureSessionManager.biometricKeyExists();
      if (keyExists) return;

      const biometryLabel =
        biometryType === BiometryTypes.FaceID
          ? 'Face ID'
          : biometryType === BiometryTypes.TouchID
          ? 'Touch ID'
          : 'Fingerprint';

      Alert.alert(
        'Enable Biometric Login',
        `Would you like to enable ${biometryLabel} for faster, secure sign-in? This creates a cryptographic key pair bound to your biometric data.`,
        [
          { text: 'Not Now', style: 'cancel' },
          {
            text: 'Enable',
            onPress: async () => {
              const enrollResult = await enrollBiometrics();
              if (enrollResult.success) {
                Alert.alert(
                  'Success',
                  `${biometryLabel} has been enabled. You can now use it to sign in securely.`
                );
              } else {
                Alert.alert('Error', 'Failed to enable biometric login. You can try again later in Settings.');
              }
            },
          },
        ]
      );
    } catch (err) {
      console.error('Biometric enrollment offer failed:', err);
    }
  };

  return (
    <View style={styles.container}>
      <View style={styles.headerContainer}>
        <Text style={styles.appTitle}>SecureApp</Text>
        <Text style={styles.subtitle}>Sign in with password</Text>
      </View>

      <View style={styles.formContainer}>
        <View style={styles.inputContainer}>
          <Text style={styles.inputLabel}>Email</Text>
          <TextInput
            style={styles.input}
            placeholder="Enter your email"
            placeholderTextColor="#999"
            value={email}
            onChangeText={setEmail}
            keyboardType="email-address"
            autoCapitalize="none"
            autoCorrect={false}
            editable={!isLoading}
          />
        </View>

        <View style={styles.inputContainer}>
          <Text style={styles.inputLabel}>Password</Text>
          <TextInput
            style={styles.input}
            placeholder="Enter your password"
            placeholderTextColor="#999"
            value={password}
            onChangeText={setPassword}
            secureTextEntry
            autoCapitalize="none"
            editable={!isLoading}
          />
        </View>

        {error && (
          <View style={styles.errorContainer}>
            <Text style={styles.errorText}>{error}</Text>
          </View>
        )}

        <TouchableOpacity
          style={[styles.loginButton, isLoading && styles.buttonDisabled]}
          onPress={handlePasswordLogin}
          disabled={isLoading}
          activeOpacity={0.7}
        >
          {isLoading ? (
            <ActivityIndicator size="small" color="#FFFFFF" />
          ) : (
            <Text style={styles.loginButtonText}>Sign In</Text>
          )}
        </TouchableOpacity>
      </View>

      {showBackButton && (
        <TouchableOpacity
          style={styles.fallbackButton}
          onPress={onBack}
          activeOpacity={0.7}
        >
          <Text style={styles.fallbackButtonText}>Back to biometric login</Text>
        </TouchableOpacity>
      )}
    </View>
  );
};

// --- Home Screen (Authenticated) ---

const HomeScreen = () => {
  const { logout, userEmail, sessionToken } = useAuth();
  const [tokenInfo, setTokenInfo] = useState(null);

  useEffect(() => {
    if (sessionToken) {
      try {
        const payload = JSON.parse(atob(sessionToken));
        setTokenInfo(payload);
      } catch {
        setTokenInfo(null);
      }
    }
  }, [sessionToken]);

  const handleLogout = () => {
    Alert.alert(
      'Sign Out',
      'This will remove your biometric keys and session. You will need to sign in again.',
      [
        { text: 'Cancel', style: 'cancel' },
        {
          text: 'Sign Out',
          style: 'destructive',
          onPress: logout,
        },
      ]
    );
  };

  return (
    <View style={styles.container}>
      <View style={styles.headerContainer}>
        <Text style={styles.appTitle}>🏠 Home</Text>
        <Text style={styles.subtitle}>You are securely authenticated</Text>
      </View>

      <View style={styles.infoCard}>
        <Text style={styles.infoTitle}>Session Info</Text>
        {userEmail && (
          <Text style={styles.infoText}>Email: {userEmail}</Text>
        )}
        {tokenInfo && (
          <>
            <Text style={styles.infoText}>
              Method: {tokenInfo.method === 'password' ? 'Password' : 'Biometric Signature'}
            </Text>
            <Text style={styles.infoText}>
              Issued: {new Date(tokenInfo.issuedAt).toLocaleString()}
            </Text>
            <Text style={styles.infoText}>
              Expires: {new Date(tokenInfo.expiresAt).toLocaleString()}
            </Text>
            <Text style={styles.infoText}>
              Signature Hash: {tokenInfo.signatureHash}
            </Text>
            <Text style={styles.infoText}>
              Verified: {tokenInfo.verified ? '✅ Yes' : '❌ No'}
            </Text>
          </>
        )}
      </View>

      <View style={styles.securityInfoCard}>
        <Text style={styles.securityInfoTitle}>🔐 Security Details</Text>
        <Text style={styles.securityInfoText}>
          • Session bound to cryptographic signature{'\n'}
          • Biometric key stored in {Platform.OS === 'ios' ? 'Secure Enclave' : 'Android Keystore'}{'\n'}
          • Token expires after 24 hours{'\n'}
          • Challenge-response prevents replay attacks
        </Text>
      </View>

      <TouchableOpacity
        style={styles.logoutButton}
        onPress={handleLogout}
        activeOpacity={0.7}
      >
        <Text style={styles.logoutButtonText}>Sign Out</Text>
      </TouchableOpacity>
    </View>
  );
};

// --- Login Navigator ---

const LoginNavigator = () => {
  const [showPasswordScreen, setShowPasswordScreen] = useState(false);
  const [hasBiometrics, setHasBiometrics] = useState(null);

  useEffect(() => {
    checkBiometrics();
  }, []);

  const checkBiometrics = async () => {
    try {
      const { available } = await rnBiometrics.isSensorAvailable();
      setHasBiometrics(available);
      if (!available) {
        setShowPasswordScreen(true);
      }
    } catch {
      setHasBiometrics(false);
      setShowPasswordScreen(true);
    }
  };

  if (hasBiometrics === null) {
    return (
      <View style={styles.loadingContainer}>
        <ActivityIndicator size="large" color="#007AFF" />
      </View>
    );
  }

  if (showPasswordScreen) {
    return (
      <PasswordLoginScreen
        onBack={() => setShowPasswordScreen(false)}
        showBackButton={hasBiometrics}
      />
    );
  }

  return (
    <BiometricLoginScreen
      onPasswordFallback={() => setShowPasswordScreen(true)}
    />
  );
};

// --- App Root ---

const AppContent = () => {
  const { isAuthenticated, isLoading } = useAuth();

  if (isLoading) {
    return (
      <View style={styles.loadingContainer}>
        <ActivityIndicator size="large" color="#007AFF" />
        <Text style={styles.loadingText}>Verifying session...</Text>
      </View>
    );
  }

  return isAuthenticated ? <HomeScreen /> : <LoginNavigator />;
};

const App = () => {
  return (
    <AuthProvider>
      <AppContent />
    </AuthProvider>
  );
};

